  const [name, setName] = useState('');
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  // Selection Fields
  const [assignedClasses, setAssignedClasses] = useState<ClassLevel[]>([]);
  const [assignedSubjects, setAssignedSubjects] = useState<Subject[]>([]);

  // Extra Fields
  const [bio, setBio] = useState('');
  const [expertise, setExpertise] = useState('');
  const [reason, setReason] = useState('');

  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const allClassLevels: ClassLevel[] = ['P6', 'P7', 'S1', 'S2', 'S3', 'S4', 'S5', 'S6'];
  const allSubjects = Object.values(Subject);

  // Helper to safely extract error message
  const getErrorMessage = (err: any) => {
    if (typeof err === 'string') return err;
    if (err instanceof Error) return err.message;

    if (err && typeof err === 'object') {
         if ('message' in err && typeof err.message === 'string') return err.message;
         if ('text' in err && typeof err.text === 'string') return err.text;
         if ('error_description' in err && typeof err.error_description === 'string') return err.error_description;
         if ('details' in err && typeof err.details === 'string') return err.details;
    }

    try {
        const json = JSON.stringify(err);
        if (json !== '{}') return json;
    } catch {
        // ignore
    }

    return 'Failed to register. Please try again.';
  };

  const toggleClass = (cls: ClassLevel) => {
      setAssignedClasses(prev => 
          prev.includes(cls) 
            ? prev.filter(c => c !== cls) 
            : [...prev, cls]
      );
  };

  const toggleSubject = (sub: Subject) => {
      setAssignedSubjects(prev =>
        prev.includes(sub)
            ? prev.filter(s => s !== sub)
            : [...prev, sub]
      );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    if(password.length < 6) {
        setError("Password must be at least 6 characters long.");
        setLoading(false);
        return;
    }

    if(assignedClasses.length === 0) {
        setError("Please select at least one class you can teach.");
        setLoading(false);
        return;
    }

    if(assignedSubjects.length === 0) {
        setError("Please select at least one subject you can teach.");
        setLoading(false);
        return;
    }

    try {
        const existing = await findUserByUsername(username);
        if (existing) {
            setError("Username already taken.");
            setLoading(false);
            return;
        }

        await registerTeacher({
            name,
            username,
            email,
            password,
            bio,
            expertise,
            reasonForJoining: reason,
            assignedClasses,
            assignedSubjects
        });

        setSuccess(true);
    } catch (err: any) {
        console.error("Registration error:", err);
        setError(getErrorMessage(err));
    } finally {
        setLoading(false);
    }
  };

  if (success) {
      useEffect(() => {
        const timer = setTimeout(() => {
            navigate('/login');
        }, 3000);
        return () => clearTimeout(timer);
      }, [navigate]);

      return (
        <div className="min-h-screen flex items-center justify-center bg-secondary dark:bg-gray-900 p-4 transition-colors duration-200">
            <div className="w-full max-w-md bg-white dark:bg-gray-800 rounded-2xl shadow-xl p-8 text-center">
